    r[FRACTAL_FRAC_HIST_240_UP] = cell_dff(r[FRACTAL_FRAC_HIST_240_UP], r[FRACTAL_FRAC_HIST_239_UP], frac_boundary);
    r[FRACTAL_FRAC_HIST_240_DN] = cell_dff(r[FRACTAL_FRAC_HIST_240_DN], r[FRACTAL_FRAC_HIST_239_DN], frac_boundary);
